import { existsSync, readFileSync, writeFileSync } from "fs";
import { join } from "path";
import {
  AUTO_STUB_PACKAGES,
  AUTO_STUB_CSS,
  type AutoStubEntry,
} from "@plugins/plugin-meta/plugins/barrel-import/core";

const GENERATED_PATH =
  "plugins/plugin-meta/plugins/barrel-import/core/internal/auto-stubs.generated.ts";

const HEADER = [
  "// DO NOT EDIT — autogenerated by `./singularity build`",
  "// (see plugins/framework/plugins/tooling/plugins/codegen/core/barrel-stubs-gen.ts).",
  "//",
  "// To add a package: edit auto-stub-packages.ts and rebuild.",
  "// The `barrel-stubs-in-sync` check fails on drift.",
].join("\n");

function resolveDtsEntry(root: string, entry: AutoStubEntry): string {
  const base = entry.resolveFrom
    ? join(root, entry.resolveFrom, "node_modules")
    : join(root, "node_modules");

  const pkgJsonPath = join(base, entry.pkg, "package.json");
  if (!existsSync(pkgJsonPath)) {
    throw new Error(
      `[barrel-stubs-gen] Cannot find ${entry.pkg}/package.json in ${base}`,
    );
  }

  const pkg = JSON.parse(readFileSync(pkgJsonPath, "utf8")) as Record<
    string,
    unknown
  >;

  if (typeof pkg.types === "string")
    return join(base, entry.pkg, pkg.types);
  if (typeof pkg.typings === "string")
    return join(base, entry.pkg, pkg.typings);

  throw new Error(
    `[barrel-stubs-gen] Cannot resolve .d.ts entry for ${entry.pkg}: no types/typings field in package.json`,
  );
}

// `export { A, B as C, type D, default as E } from './sub'`
const NAMED_RE =
  /^[ \t]*export\s+\{([^}]+)\}/gm;
// `export type { ... }` — skip the whole block
const TYPE_BLOCK_RE = /^[ \t]*export\s+type\s+\{/;
// `export declare function/class/const/enum/let/var X` or `export class X`
// (with optional indentation for ambient module blocks)
const DECL_RE =
  /^[ \t]*export\s+(?:declare\s+)?(?:abstract\s+)?(?:function|class|const|enum|let|var)\s+(\w+)/gm;
// `export * from './path'` — hard error
const STAR_RE = /^[ \t]*export\s+\*\s+from/m;
// `export namespace X` — value export
const NAMESPACE_RE =
  /^[ \t]*export\s+(?:declare\s+)?namespace\s+(\w+)/gm;

function extractExportNames(src: string, pkg: string, dtsPath: string): string[] {
  if (STAR_RE.test(src)) {
    throw new Error(
      `[barrel-stubs-gen] Package "${pkg}" uses "export * from" in its .d.ts entry ` +
        `(${dtsPath}). Auto-stubbing is not possible — Bun needs export names at ` +
        `link time and "export *" names require transitive resolution.\n` +
        `Add a manual stub for "${pkg}" in stubs.ts instead, and remove it from ` +
        `auto-stub-packages.ts.`,
    );
  }

  const names = new Set<string>();

  for (const match of src.matchAll(NAMED_RE)) {
    const line = src.slice(
      src.lastIndexOf("\n", match.index!) + 1,
      match.index! + match[0].length,
    );
    if (TYPE_BLOCK_RE.test(line)) continue;

    const inner = match[1]!;
    for (const token of inner.split(",")) {
      const t = token.trim();
      if (!t) continue;
      // Skip `type Foo` inline type re-exports
      if (t.startsWith("type ")) continue;
      // Handle `X as Y` — the exported name is Y
      const asMatch = t.match(/(?:\w+)\s+as\s+(\w+)/);
      if (asMatch) {
        names.add(asMatch[1]!);
      } else {
        const plain = t.match(/^(\w+)/);
        if (plain) names.add(plain[1]!);
      }
    }
  }

  for (const match of src.matchAll(DECL_RE)) {
    names.add(match[1]!);
  }

  for (const match of src.matchAll(NAMESPACE_RE)) {
    names.add(match[1]!);
  }

  // Filter out names that are clearly type-only but slipped through
  // (interfaces and type aliases don't produce runtime values)
  // Not needed — our regex only matches function/class/const/enum/namespace/let/var

  return Array.from(names).sort();
}

function renderPackageStub(pkg: string, exportNames: string[]): string {
  const entries = exportNames.map((n) => `      ${n}: noop,`);
  entries.push("      __esModule: true,");
  return [
    `  build.module(${JSON.stringify(pkg)}, () => ({`,
    "    exports: {",
    ...entries,
    "    },",
    '    loader: "object",',
    "  }));",
  ].join("\n");
}

export function renderBarrelStubs({ root }: { root: string }): string {
  const stubs: string[] = [];

  for (const entry of AUTO_STUB_PACKAGES) {
    const dtsPath = resolveDtsEntry(root, entry);
    const src = readFileSync(dtsPath, "utf8");
    const names = extractExportNames(src, entry.pkg, dtsPath);
    if (names.length === 0) {
      throw new Error(
        `[barrel-stubs-gen] No value exports found for "${entry.pkg}" in ${dtsPath}. ` +
          `Is the .d.ts file correct?`,
      );
    }
    stubs.push(renderPackageStub(entry.pkg, names));
  }

  const cssEntries = AUTO_STUB_CSS.map((p) => `    ${JSON.stringify(p)},`).join(
    "\n",
  );

  const body = [
    HEADER,
    "",
    "/* eslint-disable @typescript-eslint/no-explicit-any */",
    "",
    "type BuildModule = {",
    '  module(id: string, cb: () => { exports: Record<string, unknown>; loader: "object" }): void;',
    "};",
    "",
    "export function registerAutoStubs(build: BuildModule): void {",
    "  const noop = (() => {}) as any;",
    "",
    stubs.join("\n\n"),
    "",
    "  for (const mod of [",
    cssEntries,
    "  ]) {",
    '    build.module(mod, () => ({ exports: {}, loader: "object" }));',
    "  }",
    "}",
    "",
  ].join("\n");

  return body;
}

export function barrelStubsPath(root: string): string {
  return join(root, GENERATED_PATH);
}

export async function generateBarrelStubs({
  root,
}: {
  root: string;
}): Promise<void> {
  const content = renderBarrelStubs({ root });
  const outPath = barrelStubsPath(root);
  const existing = existsSync(outPath) ? readFileSync(outPath, "utf8") : "";
  if (content !== existing) {
    writeFileSync(outPath, content);
  }
}
